export type AmenityName = keyof typeof AMENITY_ICON_MAP;
export type AmenityIconFileName =
    | (typeof AMENITY_ICON_MAP)[AmenityName]
    | (typeof AMENITY_ICON_ALIAS_MAP)[keyof typeof AMENITY_ICON_ALIAS_MAP]
    | typeof DEFAULT_AMENITY_ICON_FILE;

export function toAmenityIconKey(value: string) {
    return value
        .normalize('NFKD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/&/g, ' and ')
        .replace(/\+/g, ' plus ')
        .replace(/['\u2019]/g, '')
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-+|-+$/g, '');
}

export function getAmenityIconFileName(amenityName: string): AmenityIconFileName {
    const exactMatch = AMENITY_ICON_MAP[amenityName as AmenityName];
    if (exactMatch) return exactMatch;

    const normalizedMatch = AMENITY_ICON_ALIAS_MAP[toAmenityIconKey(amenityName) as keyof typeof AMENITY_ICON_ALIAS_MAP];
    return normalizedMatch ?? DEFAULT_AMENITY_ICON_FILE;
}

export function getAmenityIcon(amenityName: string) {
    return `${AMENITY_ICON_BASE_PATH}/${getAmenityIconFileName(amenityName)}`;
}

export const getAmenityIconPath = getAmenityIcon;
